Material.Shader:

/* This is a vertex program for ...
 */

varying float setScalar;

void main()
{
  /* Transform the normal. */
  vec3 lightDirection = vec3(1.0, 0.5, 0.2);
  vec3 normal = normalize(gl_NormalMatrix*gl_Normal);
  //if(gl_Vertex.x > 0)
	//setScalar = gl_MultiTexCoord0.x - gl_Vertex.x + normal.x;//normalize(normal * gl_Color.xyz);
  //else
	setScalar = gl_MultiTexCoord0.x; //+ gl_Vertex.x + normal.x;

  gl_Position = ftransform();
}




/* This is a fragment program ...
 */
varying float setScalar;

uniform vec4 Color0;
uniform vec4 Color1;

void main()
{
	setScalar = setScalar * 12.0;
	int parity = setScalar;

	if(setScalar == 0)
	{
		gl_FragColor = Color1;
	}
	else if( setScalar > 11.9)
	{
		gl_FragColor = Color0;
	}
	else 
	{
		if(parity % 2 == 0)
			gl_FragColor = Color1;
		else
			gl_FragColor = Color0;
	}


}
